import{_ as e,o as a,c as i,a0 as r}from"./chunks/framework.NWv86GGy.js";const u=JSON.parse('{"title":"Taiwan — Country Brief","description":"Trans relocation guide for Taiwan: legal overview, visa options, cost of living, and key considerations.","frontmatter":{"layout":"doc","title":"Taiwan — Country Brief","description":"Trans relocation guide for Taiwan: legal overview, visa options, cost of living, and key considerations."},"headers":[],"relativePath":"countries/taiwan/index.md","filePath":"countries/taiwan/index.md","lastUpdated":1780601195000}'),n={name:"countries/taiwan/index.md"};function o(s,t,l,d,c,g){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="🇹🇼-taiwan" tabindex="-1"><span style="color:#fe0000;">🇹🇼 Taiwan</span> <a class="header-anchor" href="#🇹🇼-taiwan" aria-label="Permalink to &quot;&lt;span style=&quot;color: #fe0000;&quot;&gt;🇹🇼 Taiwan&lt;/span&gt;&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Capital</strong></td><td>Taipei</td></tr><tr><td><strong>Language</strong></td><td>Mandarin Chinese (some English in Taipei)</td></tr><tr><td><strong>Currency</strong></td><td>New Taiwan Dollar (TWD)</td></tr><tr><td><strong>Equaldex Score</strong></td><td>60</td></tr><tr><td><strong>Trans-Specific Rating</strong></td><td>3/5</td></tr><tr><td><strong>Last Verified</strong></td><td>June 2026</td></tr></tbody></table><h2 id="legal-overview" tabindex="-1">Legal Overview <a class="header-anchor" href="#legal-overview" aria-label="Permalink to &quot;Legal Overview&quot;">​</a></h2><p>Taiwan is the most progressive country for LGBTQ+ rights in Asia. Same-sex marriage was legalised in 2019 (first in Asia). However, trans-specific legal protections lag behind.</p><ul><li><strong>Gender Recognition:</strong> Medicalised. Surgery is currently required for legal gender marker change on ID documents. Activist groups are actively challenging this. There is no third gender option.</li><li><strong>Anti-Discrimination Law:</strong> The 2023 legal amendments provide protections based on sexual orientation and gender identity in education and some services. Employment protections are partial.</li><li><strong>Hate Crime Laws:</strong> Hate crimes based on sexual orientation or gender identity are recognised.</li><li><strong>Conversion Therapy:</strong> Not banned.</li></ul><h2 id="healthcare" tabindex="-1">Healthcare <a class="header-anchor" href="#healthcare" aria-label="Permalink to &quot;Healthcare&quot;">​</a></h2><ul><li><strong>HRT Access:</strong> Informed consent available at some clinics in Taipei. Many endocrinologists still require therapy letters. Private clinics are more flexible.</li><li><strong>Cost:</strong> TWD 1,000–3,000/month (≈ €30–90).</li></ul><h2 id="visa-pathways" tabindex="-1">Visa Pathways <a class="header-anchor" href="#visa-pathways" aria-label="Permalink to &quot;Visa Pathways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Income Req.</th><th>Processing</th><th>Leads to PR?</th></tr></thead><tbody><tr><td>Gold Card</td><td>TWD 167,000/month (≈ €5,000)</td><td>1–3 months</td><td>Yes</td></tr><tr><td>Work Visa</td><td>Job offer</td><td>2–4 months</td><td>Yes</td></tr><tr><td>Student Visa</td><td>Proof of funds</td><td>1–2 months</td><td>Possible</td></tr></tbody></table><h2 id="cost-of-living-taipei" tabindex="-1">Cost of Living (Taipei) <a class="header-anchor" href="#cost-of-living-taipei" aria-label="Permalink to &quot;Cost of Living (Taipei)&quot;">​</a></h2><p>1-bedroom: TWD 15,000–30,000/month (≈ €450–900). Monthly budget: TWD 35,000–60,000 (≈ €1,050–1,800).</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><strong>Surgery requirement</strong> for gender recognition is a major barrier</li><li><strong>Safety</strong> is excellent — Taiwan is very safe for LGBTQ+ people</li><li><strong>Geopolitical risk</strong> is a consideration for long-term planning</li><li><strong>Mandarin essential</strong> for daily life and healthcare</li><li><strong>Asylum:</strong> Not available for LGBTQ+ claims</li></ul><p><em>Sources: Taiwan Alliance to Promote Civil Partnership Rights, ILGA, Equaldex. Last verified: June 2026.</em></p>',14)])])}const p=e(n,[["render",o]]);export{u as __pageData,p as default};
